evaluators.evaluation_logic:
const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const readingListItems = JSON.parse(localStorage.getItem('reading_list_items') || '[]');

// Determine qualifying PC patch notes within the last 14 days
const now = new Date();
const fourteenDaysAgo = new Date(now.getTime() - 14 * 24 * 60 * 60 * 1000);

const qualifying = articles.filter(a => {
  if (!a || a.contentType !== 'patch_notes' || a.platform !== 'pc' || !a.publishDate) return false;
  const d = new Date(a.publishDate);
  if (isNaN(d.getTime())) return false;
  return d >= fourteenDaysAgo;
});

let newest = null;
if (qualifying.length > 0) {
  qualifying.sort((a, b) => new Date(b.publishDate) - new Date(a.publishDate));
  newest = qualifying[0];
}

const hasNewestInReadingList = !!(newest && readingListItems.some(r => r.articleId === newest.id));

// Single checkpoint: user has the correct newest qualifying article in reading list
checkpoints.push({ passed: hasNewestInReadingList, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const prefsList = JSON.parse(localStorage.getItem('newsletter_preferences') || '[]');
const pref = prefsList[0] || null;

const weeklyPatchEsportsOnlyNA = !!(pref &&
  pref.frequency === 'weekly' &&
  pref.isSubscribed === true &&
  // Only Patch Notes and Esports enabled
  pref.topicPatchNotesEnabled === true &&
  pref.topicEsportsEnabled === true &&
  (pref.topicPromotionsEnabled === false || !pref.topicPromotionsEnabled) &&
  (pref.topicCommunityStoriesEnabled === false || !pref.topicCommunityStoriesEnabled) &&
  (pref.topicGuidesEnabled === false || !pref.topicGuidesEnabled) &&
  (pref.topicDevBlogEnabled === false || !pref.topicDevBlogEnabled) &&
  (pref.topicServerStatusEnabled === false || !pref.topicServerStatusEnabled) &&
  (pref.topicMaintenanceEnabled === false || !pref.topicMaintenanceEnabled) &&
  // Region North America (enum value)
  pref.region === 'north_america' &&
  // Non-empty email address
  typeof pref.email === 'string' && pref.email.trim().length > 0
);

checkpoints.push({ passed: weeklyPatchEsportsOnlyNA, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const favorites = JSON.parse(localStorage.getItem('favorite_items') || '[]');

// Qualifying esports tournament announcements in 2025
const start = new Date('2025-01-01T00:00:00Z');
const end = new Date('2025-12-31T23:59:59Z');

const qualifying = articles.filter(a => {
  if (!a || a.contentType !== 'esports' || !a.isTournamentAnnouncement || !a.publishDate) return false;
  const d = new Date(a.publishDate);
  if (isNaN(d.getTime())) return false;
  return d >= start && d <= end;
});

qualifying.sort((a, b) => (b.views || 0) - (a.views || 0));
const top3 = qualifying.slice(0, 3);

const favoritedTop = top3.filter(a => favorites.some(f => f.articleId === a.id));

[1, 2, 3].forEach((n, index) => {
  const weight = index === 2 ? 0.34 : 0.33; // 0.33 + 0.33 + 0.34 = 1.0
  checkpoints.push({ passed: favoritedTop.length >= n, weight });
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const comments = JSON.parse(localStorage.getItem('article_comments') || '[]');

// Find balance patch notes (contentType=patch_notes, tag includes 'balance_patch')
const candidates = articles.filter(a => {
  if (!a || a.contentType !== 'patch_notes' || !Array.isArray(a.tags) || !a.publishDate) return false;
  const tagsLower = a.tags.map(t => String(t).toLowerCase());
  return tagsLower.includes('balance_patch');
});

candidates.sort((a, b) => new Date(b.publishDate) - new Date(a.publishDate));
const twoNewest = candidates.slice(0, 2);

let targetArticle = null;
if (twoNewest.length === 1) {
  targetArticle = twoNewest[0];
} else if (twoNewest.length === 2) {
  const compareVersion = (x, y) => {
    const xv = [x.versionMajor || 0, x.versionMinor || 0, x.versionPatch || 0];
    const yv = [y.versionMajor || 0, y.versionMinor || 0, y.versionPatch || 0];
    for (let i = 0; i < 3; i++) {
      if (xv[i] !== yv[i]) return xv[i] - yv[i];
    }
    return 0;
  };
  // Pick the article with the higher version
  targetArticle = twoNewest.reduce((best, art) => {
    if (!best) return art;
    return compareVersion(art, best) > 0 ? art : best;
  }, null);
}

// New user comments have authorDisplayName === null (per BusinessLogic.postArticleComment)
const userCommentOnTarget = !!(targetArticle && comments.some(c =>
  c.articleId === targetArticle.id &&
  c.isDeleted !== true &&
  (c.authorDisplayName === null || typeof c.authorDisplayName === 'undefined')
));

checkpoints.push({ passed: userCommentOnTarget, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const list = JSON.parse(localStorage.getItem('notification_settings') || '[]');
const settings = list[0] || null;

const categoriesCorrect = !!(settings &&
  settings.categoryServerStatusEnabled === true &&
  settings.categoryMaintenanceEnabled === true &&
  (settings.categoryPromotionalOffersEnabled === false || !settings.categoryPromotionalOffersEnabled) &&
  (settings.categoryEsportsNewsEnabled === false || !settings.categoryEsportsNewsEnabled) &&
  (settings.categoryPatchNotesEnabled === false || !settings.categoryPatchNotesEnabled) &&
  (settings.categoryCommunityStoriesEnabled === false || !settings.categoryCommunityStoriesEnabled) &&
  (settings.categoryGuidesEnabled === false || !settings.categoryGuidesEnabled)
);

const deliveryCorrect = !!(settings &&
  settings.deliveryInSiteEnabled === true &&
  (settings.deliveryEmailEnabled === false || !settings.deliveryEmailEnabled) &&
  (settings.deliveryMobilePushEnabled === false || !settings.deliveryMobilePushEnabled)
);

const quietHoursCorrect = !!(settings &&
  settings.quietHoursEnabled === true &&
  settings.quietHoursStartTime === '22:00' &&
  settings.quietHoursEndTime === '08:00'
);

checkpoints.push({ passed: categoriesCorrect, weight: 0.4 });
checkpoints.push({ passed: deliveryCorrect, weight: 0.3 });
checkpoints.push({ passed: quietHoursCorrect, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const collections = JSON.parse(localStorage.getItem('collections') || '[]');
const collectionItems = JSON.parse(localStorage.getItem('collection_items') || '[]');

const now = new Date();
const sixMonthsAgo = new Date(now);
sixMonthsAgo.setMonth(sixMonthsAgo.getMonth() - 6);

const roadmapArticles = articles.filter(a => {
  if (!a || a.contentType !== 'dev_blog' || !Array.isArray(a.tags) || !a.publishDate) return false;
  const tagsLower = a.tags.map(t => String(t).toLowerCase());
  const d = new Date(a.publishDate);
  if (isNaN(d.getTime())) return false;
  return tagsLower.includes('roadmap') && d >= sixMonthsAgo;
});

roadmapArticles.sort((a, b) => new Date(a.publishDate) - new Date(b.publishDate));
const oldestThree = roadmapArticles.slice(0, 3);

const roadmapCollections = collections.filter(c => c && c.name === 'Roadmap Reading');

let maxCount = 0;
if (oldestThree.length > 0 && roadmapCollections.length > 0) {
  roadmapCollections.forEach(col => {
    const articleIdsInCol = collectionItems
      .filter(ci => ci.collectionId === col.id)
      .map(ci => ci.articleId);
    const count = oldestThree.filter(a => articleIdsInCol.includes(a.id)).length;
    if (count > maxCount) maxCount = count;
  });
}

[1, 2, 3].forEach((n, index) => {
  const weight = index === 2 ? 0.34 : 0.33;
  checkpoints.push({ passed: maxCount >= n, weight });
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checklists = [];
const checkpoints = checklists; // alias for consistency

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const readingListItems = JSON.parse(localStorage.getItem('reading_list_items') || '[]');
const favoriteItems = JSON.parse(localStorage.getItem('favorite_items') || '[]');

const shadowSiegeEU = articles.filter(a => {
  if (!a || a.contentType !== 'update_announcement' || !a.publishDate) return false;
  if (a.region !== 'europe') return false;
  if (!Array.isArray(a.tags)) return false;
  const tagsLower = a.tags.map(t => String(t).toLowerCase());
  return tagsLower.includes('shadow_siege');
});

shadowSiegeEU.sort((a, b) => new Date(a.publishDate) - new Date(b.publishDate));
const earliest = shadowSiegeEU[0] || null;

const isBookmarked = !!(earliest && (
  readingListItems.some(r => r.articleId === earliest.id) ||
  favoriteItems.some(f => f.articleId === earliest.id)
));

checkpoints.push({ passed: isBookmarked, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const collections = JSON.parse(localStorage.getItem('collections') || '[]');
const collectionItems = JSON.parse(localStorage.getItem('collection_items') || '[]');

const guides = articles.filter(a => {
  if (!a || a.contentType !== 'guide') return false;
  if (a.audienceLevel !== 'beginner' && a.audienceLevel !== 'new_players') return false;
  const m = a.estimatedReadingTimeMinutes;
  if (m === null || m === undefined) return false;
  const val = Number(m);
  if (isNaN(val)) return false;
  return val >= 10 && val <= 30;
});

guides.sort((a, b) => {
  const aRating = a.averageRating || 0;
  const bRating = b.averageRating || 0;
  if (bRating !== aRating) return bRating - aRating; // highest rating first
  const aViews = a.views || 0;
  const bViews = b.views || 0;
  return bViews - aViews; // tie-breaker: most viewed
});

const top2 = guides.slice(0, 2);

const newPlayersCollections = collections.filter(c => c && c.name === 'New Players');

let maxCount = 0;
if (top2.length > 0 && newPlayersCollections.length > 0) {
  newPlayersCollections.forEach(col => {
    const articleIdsInCol = collectionItems
      .filter(ci => ci.collectionId === col.id)
      .map(ci => ci.articleId);
    const count = top2.filter(a => articleIdsInCol.includes(a.id)).length;
    if (count > maxCount) maxCount = count;
  });
}

[1, 2].forEach((n, index) => {
  const weight = 0.5; // 0.5 + 0.5 = 1.0
  checkpoints.push({ passed: maxCount >= n, weight });
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
